import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Show {
  event: string;
  venue: string;
  date: string;
  ticketAvailability: string;
}

interface EventData {
  upcomingShows: Show[];
}

export default function Widget() {
  const eventData = response.data as EventData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FFC107' }}>
            Upcoming Shows
          </Typography>

          <Stack spacing={1.5}>
            {eventData.upcomingShows.map((show, index) => (
              <Box key={index} sx={{ borderBottom: '1px solid #444', pb: 1 }}>
                <Typography variant="body1" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                  {show.event}
                </Typography>
                <Typography variant="body2" sx={{ color: '#BDBDBD', mb: 0.5 }}>
                  {show.venue} - {new Date(show.date).toLocaleDateString()}
                </Typography>
                <Chip
                  label={show.ticketAvailability}
                  sx={{
                    fontSize: '10px',
                    bgcolor: show.ticketAvailability === 'Available' ? '#4CAF50' : show.ticketAvailability === 'Sold Out' ? '#F44336' : '#FFC107',
                    color: '#FFFFFF',
                  }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
